var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"크윽……?!","JPN":"くうっ……！？","ENG":"Urgh?!","TWN":"咳咳……？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"널 지켜 줄 침식체는 이제 없다, 그림자.","JPN":"貴様を守ってくれる侵食体はもういない、シャドウ。","ENG":"Your henchmen are no more, Shadow.","TWN":"已經沒有侵蝕體可以保護你了，暗影。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그만! 멈춰 줘! 내가 잘못했어! 그냥 얌전히 떠날 테니까!","JPN":"待って！　やめて！　あたしが悪かった！　大人しくここを離れるから！","ENG":"No! Stop! Don't hurt me! I'll leave...!","TWN":"住手！別再打了！都是我不好！我會乖乖離開！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"……라고 할 줄 알았냐!","JPN":"……なんて言うわけないでしょ！","ENG":"Did you think I'd beg like that?!","TWN":"……你以為我會這麼說嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이런! 모두 귀를 막아!","JPN":"しまった！　みんな耳を塞いで！","ENG":"Crap! Cover your ears!","TWN":"糟糕！大家捂住耳朵！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"아하하하, 늦었어!","JPN":"あははは、もう遅いわ！","ENG":"Ah hah hah hah!! It’s too late!","TWN":"哈哈哈哈，來不及囉！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"응?","JPN":"え？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐야. 아무 일도 안 일어나잖아?","JPN":"何だ。なにも起こらないじゃねえか。","ENG":"Nothing's happening.","TWN":"搞什麼，什麼事都沒發生嘛？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"와트 씨? 혹시 제 손가락이 몇 개인지 아시겠어요?","JPN":"ワットさん？　僕の指、何本かわかります？","ENG":"Mr. Watt? Can you tell me how many fingers I'm holding up?","TWN":"華特先生？你看我有幾隻手指？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"한 개…","JPN":"一本……","ENG":"One...","TWN":"一隻…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"가 아니라, 이 자식이 버릇없게 어른한테 무슨 짓이야?!","JPN":"じゃなくて、この野郎、大人に向かって失礼だな！？","ENG":"H-hey! Did you just flip me the bird, you little brat?!","TWN":"不對，你這臭小子，敢捉弄大人？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 다행히 멀쩡하신 것 같은데요?","JPN":"へへ、なんともないようですね。","ENG":"Heh heh! Well, at least your not hallucinating, right?","TWN":"嘿嘿，幸好你沒事。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"어라? 그런가?","JPN":"あれ？　そうか？","ENG":"Huh? Is that why...?","TWN":"喔？是嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"뭐야? 어떻게 된 거지? 왜 내 연주가 통하지 않는 거야?","JPN":"何よ？　どういうことなの？　どうしてあたしの演奏が通じないのよ。","ENG":"Huh? What's happening?! Why isn't my performance working?!","TWN":"怎麼搞的？這是怎麼回事？爲什麼我的演奏無效？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"불길한 기운이 느껴져서 떨쳐냈는데, 효과가 있었나 보군.","JPN":"不吉なものが感じられて振り払ったが、効果があったようだな。","ENG":"I blocked off the ominous aura. I guess it worked.","TWN":"覺得有不好的預感，就把它甩開，看來有效呢。"},"stage":{"bg":"KINGDOM_05","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"너…… 그 황금빛은…?","JPN":"あんた……その黄金の光は……？","ENG":"You... That golden light...!","TWN":"你…… 金黃色的光芒……？"},"stage":{"bg":"KINGDOM_05","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"설마……. 성유물이라고?","JPN":"まさか……聖遺物？","ENG":"Is that... the Holy Relic?","TWN":"難道是…… 聖遺物嗎？"},"stage":{"bg":"KINGDOM_05","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……성공했어.","JPN":"……成功したんだ。","ENG":"...It worked.","TWN":"……成功了！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"심장에 박혀 있던 성유물이 지휘관의 몸을 받아들인 거야!","JPN":"心臓に刺さっていた聖遺物が指揮官の体を受け入れたんだ！","ENG":"Curian's body was accepted as a vessel by the Holy Relic embedded in his heart!","TWN":"嵌入心臟的聖遺物與指揮官的身體相容！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"심장에 성유물이 박혀? 그게 무슨 헛소리…!","JPN":"心臓に聖遺物が刺さる？　何くだらないこと……！","ENG":"Embedded in his heart?! What kind of...","TWN":"在心臟裡嵌入聖遺物？在胡說八道什麼…！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"헛… 소리…","JPN":"くだらない……こと……","ENG":"Nonsense... Is─","TWN":"胡… 說…"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"지금 그 커다란 창으로 사람을 찌른 거야?","JPN":"今、そのおっきい槍で人を突いたの？","ENG":"Did you just stab a person with that giant spear?","TWN":"你現在是拿那把槍在刺人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"어떡해~ 진짜 아프겠다~","JPN":"どうしよう～めっちゃ痛そう～","ENG":"Oh no! That must have weally hwurt...","TWN":"怎麼辦～一定很痛～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CURIAN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"너…… 설마 큐리안 놈의 부관?","JPN":"あんた……まさかキュリアンの副官なの？","ENG":"You... You're Curian's adjutant, aren't you?","TWN":"你… 難道是庫里安的副隊長？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그럴 리가! 넌 분명 큐리안 손에 죽었어!","JPN":"そんなはずないわ！　あんたは確かにキュリアンの手で殺された！","ENG":"Impossible! I saw Curian kill you!","TWN":"怎麼可能！你明明就死於庫里安之手！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"왜 아직도 살아 있는 거지?! 왜 그 때와 똑같은 낯짝으로 내 앞에 서 있는 거냐고!!","JPN":"どうしてまだ生きてるの！？　なんであの時と同じ顔であたしの前に立ってるのよ！！","ENG":"How are you still alive?! And how are you standing in front of me looking exactly the same as 20 years ago?!","TWN":"你爲什麼還活著？！爲什麼出現在我面前的是同一張臉！！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그야 왕실이 열쇠의 정체를 알리지 않은 덕분이지. 참 다행이지 않나?","JPN":"王室が鍵の正体を明かしていなかったおかげだ。本当によかったと思わないか？","ENG":"Yes, I was able to survive because the Key's identity was kept hidden. Isn't that fortunate?","TWN":"多虧皇室公開鑰匙到底是什麼，很幸運吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"몰랐던 건 네 녀석도 마찬가지잖아! 열쇠의 정체는 총사대장만 알고 있었어!","JPN":"知らなかったのはあんたも同じでしょ！　鍵の正体は銃士隊長だけが知ってたんだから！","ENG":"You didn't know either! The only one who knew was the General Musketeer!","TWN":"你還不是不知道！只有隊長才知道鑰匙是什麼！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그걸 왜 큐리안도 아니라 평범한 인간 따위가 가지고 있는 거냐고!","JPN":"それを、なんでキュリアンでもない普通の人間なんかが持ってるのよ！","ENG":"Why is it that a puny human like you is carrying it around?!","TWN":"爲什麼不是庫里安，而是在普通人的手裡！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"착각하고 있군.","JPN":"勘違いしてるな。","ENG":"You're mistaken.","TWN":"你搞錯了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"열쇠를 지키는 건 총사대장 한 명에게 맡겨진 임무가 아니다.","JPN":"鍵を守るのは銃士隊長一人に与えられた任務ではない。","ENG":"The responsibility to protect the Key was not entrusted to General Musketeer alone.","TWN":"守護鑰匙的任務並非只交付給隊長一人，"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우리 제1 총사대 전원이 받은 임무지.","JPN":"我々、第1銃士隊全員に与えられた任務だ。","ENG":"The entire 1st Musketeer Division was given this mission.","TWN":"而是交付給我們第1射擊隊所有人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그러니 우리 중 단 한 명이라도 살아 있는 한, 성유물은 가져갈 수 없다. 그림자.","JPN":"だから我々の中で一人でも生きているかぎり、聖遺物を奪うことはできない。シャドウ。","ENG":"So, Shadow, you can't take the Holy Relic from us as long as one of us is still alive.","TWN":"因此只要我們當中有一人還活著，就別想帶走聖遺物，暗影。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"하하… 아하하…","JPN":"はは……あはは……","ENG":"Ha... Ah Ha ha...","TWN":"哈哈… 哈哈哈…"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"웃기는 소리 하지 마! 아무것도 모르는 주제에!","JPN":"ふざけるな！　何も知らないくせに！","ENG":"Don't be ridiculous! You're just a disposable pawn!","TWN":"笑話！你根本什麼都不知道。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"빈손으로 돌아가면…… 지휘자님이……!","JPN":"手ぶらで帰ったら……マエストロが……！","ENG":"If I got back empty handed... Then the Chief Conductor will...!","TWN":"若是空手而歸……那指揮家……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"놈이… 변하고 있어요.","JPN":"やつが……変わってます。","ENG":"She's... Changing.","TWN":"這傢伙…正在變化。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐야? 저 거대한 흉물은…?","JPN":"何だ？　あの巨大で醜い姿は……？","ENG":"What?! That huge monster is her?!","TWN":"那什麼巨大的怪物…？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한나의 몸으로는 제 형상을 유지하는 데 한계가 왔나 보군.","JPN":"ハンナの体では元の姿を維持できなくなったようだな。","ENG":"She must've reached the limit with Hanna's body.","TWN":"利用漢娜的身體維持自己的形體，似乎已經到達極限。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"다들 당황할 것 없어. 그림자를 상대하는 건 이미 겪어 본 일이잖아?","JPN":"みんな、慌てるな。シャドウの相手はもう経験済みだろう？","ENG":"Don't panic. We have experience dealing with Shadows already, remember?","TWN":"大家不用慌張，之前不是已經對付過暗影嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지휘관? 작전은 이전과 같겠지?","JPN":"指揮官？　作戦は前と同じだよね？","ENG":"Commander? Is the plan same as last time?","TWN":"指揮官？戰略跟以前一樣吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"선봉은 내가 맡겠다. 엄호를 부탁하지.","JPN":"私が先鋒に立つ。援護を頼む。","ENG":"I'll take the lead. Cover me.","TWN":"我來當先鋒，掩護就交給你。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……전원! 이번이 마지막 전투다!","JPN":"……総員！　今度が最後の戦闘だ！","ENG":"...Men! This is the final battle!","TWN":"……大家！這是最後一場戰鬥！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"우리는 노르드나빅의 벽! 고향의 터전을 지키는 최후의 보루!","JPN":"我々はノルドナビックの壁！　故郷を守る最後の砦！","ENG":"We are the wall of Nordnavik! The last line of defense for our country and homeland!","TWN":"我們是諾爾德萊比的城牆！是守護家鄉的最後堡壘！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"죽지 말고 살아남아! 그리고 다시 돌아가자!","JPN":"死なずに生き残れ！　そしてまた帰ろう！","ENG":"Fight! Survive! And may we all go back home safely!","TWN":"別死，要活下去！還要回去！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"앞서 쓰러져간 이들의 이름이! 그대들의 의지와 함께하길!","JPN":"先に倒れていった者たちの名が！　君たちの意志と共にあらんことを！","ENG":"May the names of those who have fallen before you be with your determination!","TWN":"願先前倒下之人之名！願與你們的意志同在！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"우리의 이름이! 앞서 쓰러져간 이들의 의지와 함께하길!","JPN":"我々の名が！　先に倒れていった者たちの意志と共にあらんことを！","ENG":"May our names be with the determination of those who have fallen before us!","TWN":"願我們的名字！先前倒下之人之意志同在！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"가자, 허밋.","JPN":"行こう、ハーミット。","ENG":"Let's go, Hermit!","TWN":"走吧，赫米特。"},"stage":{"bg":"KINGDOM_05","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우리의 길고 길었던 임무에 종지부를 찍는 거다.","JPN":"我々の長かった任務に終止符を打つんだ。","ENG":"This is the day we finally fulfill our long-awaited mission.","TWN":"爲我們漫長的任務畫上句號。"},"stage":{"bg":"KINGDOM_05","bgm":"THEMA_CURIAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};